    "footer.brandLinePre": "Branded residences at",
    "footer.brandLineMid": ", on Golf Course Extension Road — engineered in partnership with",
    "footer.legalBody": "This website is for information only and does not constitute an offer or a contract. All imagery is artistic and indicative. Areas, specifications and figures are subject to the official RERA listing and may change at the developer's discretion. See our",
    "footer.disclaimerLink": "disclaimer",
    "footer.rightsReserved": "All rights reserved.",
    "footer.developedBy": "Developed by",
